arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9: HasIndex throws for Cosmos entities — remove it.
    // Cosmos DB indexing is managed via the container's indexing policy.

    // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
    // Preserve the old name so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9: id no longer includes the discriminator (was "Blog|1", now "1").
    // Preserve the old compound format so existing documents can still be found.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

